import{_ as a,o as e,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"macOS Dev Setup","description":"","frontmatter":{"summary":"Setup guide for developers working on the OpenSoul macOS app","read_when":["Setting up the macOS development environment"],"title":"macOS Dev Setup"},"headers":[],"relativePath":"platforms/mac/dev-setup.md","filePath":"platforms/mac/dev-setup.md","lastUpdated":1771906665000}'),t={name:"platforms/mac/dev-setup.md"};function p(l,s,r,o,h,d){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="macos-developer-setup" tabindex="-1"><a class="header-anchor" href="#macos-developer-setup">#</a> macOS Developer Setup</h1><p>This guide covers the necessary steps to build and run the OpenSoul macOS application from source.</p><h2 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites">#</a> Prerequisites</h2><p>Before building the app, ensure you have the following installed:</p><ol><li><strong>Xcode 26.2+</strong>: Required for Swift development.</li><li><strong>Node.js 22+ &amp; pnpm</strong>: Required for the gateway, CLI, and packaging scripts.</li></ol><h2 id="_1-install-dependencies" tabindex="-1"><a class="header-anchor" href="#_1-install-dependencies">#</a> 1. Install Dependencies</h2><p>Install the project-wide dependencies:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="_2-build-and-package-the-app" tabindex="-1"><a class="header-anchor" href="#_2-build-and-package-the-app">#</a> 2. Build and Package the App</h2><p>To build the macOS app and package it into <code>dist/OpenSoul.app</code>, run:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/package-mac-app.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>If you don&#39;t have an Apple Developer ID certificate, the script will automatically use <strong>ad-hoc signing</strong> (<code>-</code>).</p><p>For dev run modes, signing flags, and Team ID troubleshooting, see the macOS app README: <a href="https://github.com/NJX-njx/opensoul/blob/main/apps/macos/README.md" target="_blank" rel="noreferrer">https://github.com/NJX-njx/opensoul/blob/main/apps/macos/README.md</a></p><blockquote><p><strong>Note</strong>: Ad-hoc signed apps may trigger security prompts. If the app crashes immediately with &quot;Abort trap 6&quot;, see the <a href="#troubleshooting">Troubleshooting</a> section.</p></blockquote><h2 id="_3-install-the-cli" tabindex="-1"><a class="header-anchor" href="#_3-install-the-cli">#</a> 3. Install the CLI</h2><p>The macOS app expects a global <code>opensoul</code> CLI install to manage background tasks.</p><p><strong>To install it (recommended):</strong></p><ol><li>Open the OpenSoul app.</li><li>Go to the <strong>General</strong> settings tab.</li><li>Click <strong>&quot;Install CLI&quot;</strong>.</li></ol><p>Alternatively, install it manually:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">versio</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting">#</a> Troubleshooting</h2><h3 id="build-fails-toolchain-or-sdk-mismatch" tabindex="-1"><a class="header-anchor" href="#build-fails-toolchain-or-sdk-mismatch">#</a> Build Fails: Toolchain or SDK Mismatch</h3><p>The macOS app build expects the latest macOS SDK and Swift 6.2 toolchain.</p><p><strong>System dependencies (required):</strong></p><ul><li><strong>Latest macOS version available in Software Update</strong> (required by Xcode 26.2 SDKs)</li><li><strong>Xcode 26.2</strong> (Swift 6.2 toolchain)</li></ul><p><strong>Checks:</strong></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xcodebuild</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xcrun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> swift</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>If versions don’t match, update macOS/Xcode and re-run the build.</p><h3 id="app-crashes-on-permission-grant" tabindex="-1"><a class="header-anchor" href="#app-crashes-on-permission-grant">#</a> App Crashes on Permission Grant</h3><p>If the app crashes when you try to allow <strong>Speech Recognition</strong> or <strong>Microphone</strong> access, it may be due to a corrupted TCC cache or signature mismatch.</p><p><strong>Fix:</strong></p><ol><li><p>Reset the TCC permissions:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tccutil</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> All</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ai.opensoul.mac.debug</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>If that fails, change the <code>BUNDLE_ID</code> temporarily in <a href="https://github.com/NJX-njx/opensoul/blob/main/scripts/package-mac-app.sh" target="_blank" rel="noreferrer"><code>scripts/package-mac-app.sh</code></a> to force a &quot;clean slate&quot; from macOS.</p></li></ol><h3 id="gateway-starting-indefinitely" tabindex="-1"><a class="header-anchor" href="#gateway-starting-indefinitely">#</a> Gateway &quot;Starting...&quot; indefinitely</h3><p>If the gateway status stays on &quot;Starting...&quot;, check if a zombie process is holding the port:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># If you’re not using a LaunchAgent (dev mode / manual runs), find the listener:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -nP</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iTCP:18789</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sTCP:LISTEN</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>If a manual run is holding the port, stop that process (Ctrl+C). As a last resort, kill the PID you found above.</p>`,36)])])}const g=a(t,[["render",p]]);export{u as __pageData,g as default};
